/* The Pilot Lounge - Instrument Rating question bank.
   Same schema as data/private.js: { id, acs, q, choices[], a (index of correct), src{doc, ref, url, quote} }.
   Facts and quotes trace to FAA public-domain references and the ACS (FAA-S-ACS-8C).
   To extend coverage, add objects to the questions array. */
window.PILOT_LOUNGE = window.PILOT_LOUNGE || {};
window.PILOT_LOUNGE.instrument = {
  "title": "Instrument Rating",
  "acsDoc": "FAA-S-ACS-8C",
  "questions": [
    {"id":"ir-001","acs":"IR.I.A","q":"What certificate must a person already hold, or be concurrently applying for, when applying for an instrument-airplane rating?","choices":["A student pilot certificate with a solo cross-country endorsement","A commercial pilot certificate","At least a current private pilot certificate with an airplane rating appropriate to the instrument rating sought"],"a":2,"src":{"doc":"14 CFR 61.65","ref":"Instrument rating requirements","url":"https://www.ecfr.gov/current/title-14/section-61.65","quote":"A person who applies for an instrument rating must: (1) Hold at least a current private pilot certificate, or be concurrently applying for a private pilot certificate, with an airplane, helicopter, or powered-lift rating appropriate to the instrument rating sought. (14 CFR 61.65(a)(1))"}},
    {"id":"ir-002","acs":"IR.I.A","q":"For the instrument-airplane rating, how much actual or simulated instrument time must an applicant have logged in the areas of operation?","choices":["40 hours, of which 15 must have been received from an authorized instructor who holds an instrument-airplane rating","50 hours, all of which must be in actual instrument conditions","20 hours, of which 5 must be with an instructor"],"a":0,"src":{"doc":"14 CFR 61.65","ref":"Aeronautical experience for the instrument-airplane rating","url":"https://www.ecfr.gov/current/title-14/section-61.65","quote":"Forty hours of actual or simulated instrument time in the areas of operation listed in paragraph (c) of this section, of which 15 hours must have been received from an authorized instructor who holds an instrument-airplane rating. (14 CFR 61.65(d)(2))"}},
    {"id":"ir-003","acs":"IR.I.A","q":"How much cross-country time as pilot in command is required for the instrument-airplane rating, absent the combined private-and-instrument provision?","choices":["100 hours of cross-country time as pilot in command","25 hours of cross-country time in any category aircraft","50 hours of cross-country time as pilot in command, of which 10 hours must have been in an airplane"],"a":2,"src":{"doc":"14 CFR 61.65","ref":"Aeronautical experience for the instrument-airplane rating","url":"https://www.ecfr.gov/current/title-14/section-61.65","quote":"Except as provided in paragraph (g) of this section, 50 hours of cross-country time as pilot in command, of which 10 hours must have been in an airplane. (14 CFR 61.65(d)(1))"}},
    {"id":"ir-004","acs":"IR.I.A","q":"The long instrument training cross-country for the instrument-airplane rating must be a flight of how far along airways or by directed routing?","choices":["100 nautical miles","150 nautical miles","250 nautical miles"],"a":2,"src":{"doc":"14 CFR 61.65","ref":"Instrument training cross-country requirement","url":"https://www.ecfr.gov/current/title-14/section-61.65","quote":"A flight of 250 nautical miles along airways or by directed routing from an air traffic control facility; (B) An instrument approach at each airport; and (C) Three different kinds of approaches with the use of navigation systems. (14 CFR 61.65(d)(2)(ii))"}},
    {"id":"ir-005","acs":"IR.I.A","q":"To remain current to act as pilot in command under IFR, within what period must a pilot have performed and logged the required instrument experience?","choices":["Within the preceding 12 calendar months","Within the preceding 24 calendar months","Within the 6 calendar months preceding the month of the flight"],"a":2,"src":{"doc":"14 CFR 61.57","ref":"Recent instrument experience","url":"https://www.ecfr.gov/current/title-14/section-61.57","quote":"Within the 6 calendar months preceding the month of the flight, that person performed and logged at least the following tasks and iterations in an airplane, powered-lift, helicopter, or airship, as appropriate, for the instrument rating privileges to be maintained. (14 CFR 61.57(c)(1))"}},
    {"id":"ir-006","acs":"IR.I.A","q":"Which tasks must be performed and logged to maintain instrument recency of experience?","choices":["Two precision approaches and one missed approach","Six instrument approaches, holding procedures and tasks, and intercepting and tracking courses through the use of navigational electronic systems","Three instrument approaches and one holding pattern"],"a":1,"src":{"doc":"14 CFR 61.57","ref":"Recent instrument experience tasks","url":"https://www.ecfr.gov/current/title-14/section-61.57","quote":"(i) Six instrument approaches. (ii) Holding procedures and tasks. (iii) Intercepting and tracking courses through the use of navigational electronic systems. (14 CFR 61.57(c)(1))"}},
    {"id":"ir-007","acs":"IR.I.A","q":"A pilot who has not met the instrument experience requirements for more than how long may reestablish currency only by completing an instrument proficiency check?","choices":["More than six calendar months","More than 12 calendar months","More than 90 days"],"a":0,"src":{"doc":"14 CFR 61.57","ref":"Instrument proficiency check","url":"https://www.ecfr.gov/current/title-14/section-61.57","quote":"A person who has failed to meet the instrument experience requirements of paragraph (c) of this section for more than six calendar months may reestablish instrument currency only by completing an instrument proficiency check. (14 CFR 61.57(d)(1))"}},
    {"id":"ir-008","acs":"IR.I.B","q":"Before beginning any flight, what is each pilot in command required to do regarding flight information?","choices":["Review only the destination weather","File a flight plan in all cases","Become familiar with all available information concerning that flight"],"a":2,"src":{"doc":"14 CFR 91.103","ref":"Preflight action","url":"https://www.ecfr.gov/current/title-14/section-91.103","quote":"Each pilot in command shall, before beginning a flight, become familiar with all available information concerning that flight. (14 CFR 91.103)"}},
    {"id":"ir-009","acs":"IR.I.B","q":"Under the alternate requirement rule, an alternate airport need not be filed if forecasts indicate that, for at least 1 hour before and 1 hour after the ETA, what conditions will exist (for aircraft other than helicopters)?","choices":["The ceiling will be at least 2,000 feet above the airport elevation and the visibility at least 3 statute miles","The ceiling will be at least 3,000 feet and the visibility at least 5 statute miles","The ceiling will be at least 1,000 feet and the visibility at least 3 statute miles"],"a":0,"src":{"doc":"14 CFR 91.169","ref":"Alternate airport (1-2-3 rule)","url":"https://www.ecfr.gov/current/title-14/section-91.169","quote":"For aircraft other than helicopters. For at least 1 hour before and for 1 hour after the estimated time of arrival, the ceiling will be at least 2,000 feet above the airport elevation and the visibility will be at least 3 statute miles. (14 CFR 91.169(b)(2)(i))"}},
    {"id":"ir-010","acs":"IR.I.B","q":"When an instrument approach procedure is published for the alternate and no alternate minimums are specified, what are the standard alternate minimums for a precision approach procedure?","choices":["Ceiling 600 feet and visibility 2 statute miles","Ceiling 800 feet and visibility 2 statute miles","Ceiling 400 feet and visibility 1 statute mile"],"a":0,"src":{"doc":"14 CFR 91.169","ref":"IFR alternate airport weather minima","url":"https://www.ecfr.gov/current/title-14/section-91.169","quote":"For a precision approach procedure. Ceiling 600 feet and visibility 2 statute miles. (14 CFR 91.169(c)(1)(i)(A))"}},
    {"id":"ir-011","acs":"IR.I.B","q":"What are the standard alternate minimums for a nonprecision approach procedure (aircraft other than helicopters)?","choices":["Ceiling 600 feet and visibility 2 statute miles","Ceiling 1,000 feet and visibility 3 statute miles","Ceiling 800 feet and visibility 2 statute miles"],"a":2,"src":{"doc":"14 CFR 91.169","ref":"IFR alternate airport weather minima","url":"https://www.ecfr.gov/current/title-14/section-91.169","quote":"For a nonprecision approach procedure. Ceiling 800 feet and visibility 2 statute miles. (14 CFR 91.169(c)(1)(i)(B))"}},
    {"id":"ir-012","acs":"IR.I.C","q":"How much fuel must a civil aircraft carry to operate in IFR conditions when an alternate is required?","choices":["Enough to reach the destination plus 1 hour reserve, with no alternate fuel required","Enough to reach the destination plus 30 minutes reserve","Enough to complete the flight to the first airport of intended landing, then to the alternate, then 45 minutes at normal cruising speed"],"a":2,"src":{"doc":"14 CFR 91.167","ref":"Fuel requirements for flight in IFR conditions","url":"https://www.ecfr.gov/current/title-14/section-91.167","quote":"No person may operate a civil aircraft in IFR conditions unless it carries enough fuel to (1) Complete the flight to the first airport of intended landing; (2) Except as provided in paragraph (b) of this section, fly from that airport to the alternate airport; and (3) Fly after that for 45 minutes at normal cruising speed. (14 CFR 91.167(a))"}},
    {"id":"ir-013","acs":"IR.I.C","q":"For minimum altitudes for IFR operations over non-mountainous terrain where no minimum altitude is otherwise prescribed, what altitude must be maintained?","choices":["500 feet above the highest obstacle within 5 nautical miles","1,000 feet above the highest obstacle within a horizontal distance of 4 nautical miles from the course to be flown","2,000 feet above the highest obstacle within 4 nautical miles"],"a":1,"src":{"doc":"14 CFR 91.177","ref":"Minimum altitudes for IFR operations","url":"https://www.ecfr.gov/current/title-14/section-91.177","quote":"In any other case, an altitude of 1,000 feet above the highest obstacle within a horizontal distance of 4 nautical miles from the course to be flown. (14 CFR 91.177(a)(2)(ii))"}},
    {"id":"ir-014","acs":"IR.I.C","q":"Over a designated mountainous area, where no minimum altitude is otherwise prescribed, what is the minimum IFR altitude?","choices":["2,000 feet above the highest obstacle within a horizontal distance of 4 nautical miles from the course to be flown","1,000 feet above the highest obstacle within 4 nautical miles","1,500 feet above the highest obstacle within 5 nautical miles"],"a":0,"src":{"doc":"14 CFR 91.177","ref":"Minimum altitudes for IFR operations","url":"https://www.ecfr.gov/current/title-14/section-91.177","quote":"In the case of operations over an area designated as a mountainous area in part 95 of this chapter, an altitude of 2,000 feet above the highest obstacle within a horizontal distance of 4 nautical miles from the course to be flown. (14 CFR 91.177(a)(2)(i))"}},
    {"id":"ir-015","acs":"IR.I.C","q":"What does the Minimum En Route IFR Altitude (MEA) assure between radio fixes?","choices":["Communications coverage only, with no obstacle protection","Radar coverage from ATC at all times","Acceptable navigational signal coverage and obstacle clearance requirements between those fixes"],"a":2,"src":{"doc":"Pilot/Controller Glossary","ref":"Minimum En Route IFR Altitude (MEA)","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-m.html","quote":"MINIMUM EN ROUTE IFR ALTITUDE (MEA)- The lowest published altitude between radio fixes which assures acceptable navigational signal coverage and meets obstacle clearance requirements between those fixes. (Pilot/Controller Glossary)"}},
    {"id":"ir-016","acs":"IR.I.C","q":"The Minimum Obstruction Clearance Altitude (MOCA) assures acceptable navigational signal coverage only within what distance of a VOR?","choices":["Within 25 statute (22 nautical) miles of a VOR","Within 40 nautical miles of a VOR","Within 10 statute miles of a VOR"],"a":0,"src":{"doc":"Pilot/Controller Glossary","ref":"Minimum Obstruction Clearance Altitude (MOCA)","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-m.html","quote":"MINIMUM OBSTRUCTION CLEARANCE ALTITUDE (MOCA)- The lowest published altitude in effect between radio fixes on VOR airways, off-airway routes, or route segments which meets obstacle clearance requirements for the entire route segment and which assures acceptable navigational signal coverage only within 25 statute (22 nautical) miles of a VOR. (Pilot/Controller Glossary)"}},
    {"id":"ir-017","acs":"IR.I.C","q":"What is a Minimum Crossing Altitude (MCA)?","choices":["The minimum altitude for radar vectoring","The lowest altitude at certain fixes at which an aircraft must cross when proceeding in the direction of a higher MEA","The lowest altitude authorized for an instrument approach"],"a":1,"src":{"doc":"Pilot/Controller Glossary","ref":"Minimum Crossing Altitude (MCA)","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-m.html","quote":"MINIMUM CROSSING ALTITUDE (MCA)- The lowest altitude at certain fixes at which an aircraft must cross when proceeding in the direction of a higher minimum en route IFR altitude (MEA). (Pilot/Controller Glossary)"}},
    {"id":"ir-018","acs":"IR.II.A","q":"Which of the following is required equipment for flight under instrument flight rules?","choices":["A flight director","A gyroscopic rate-of-turn indicator (with limited exceptions for certain third attitude instrument systems)","A radar altimeter"],"a":1,"src":{"doc":"14 CFR 91.205","ref":"IFR instrument and equipment requirements","url":"https://www.ecfr.gov/current/title-14/section-91.205","quote":"For IFR flight, the following instruments and equipment are required: Gyroscopic rate-of-turn indicator, except on the following aircraft. (14 CFR 91.205(d)(3))"}},
    {"id":"ir-019","acs":"IR.II.A","q":"Which instrument must be installed for IFR flight under 14 CFR 91.205(d)?","choices":["A radio magnetic indicator","A sensitive altimeter adjustable for barometric pressure","A weather radar display"],"a":1,"src":{"doc":"14 CFR 91.205","ref":"IFR instrument and equipment requirements","url":"https://www.ecfr.gov/current/title-14/section-91.205","quote":"For IFR flight, the following instruments and equipment are required: Sensitive altimeter adjustable for barometric pressure. (14 CFR 91.205(d)(5))"}},
    {"id":"ir-020","acs":"IR.II.A","q":"Under 14 CFR 91.205(d), the clock required for IFR flight must display what?","choices":["Hours and minutes only","Hours, minutes, and seconds with a sweep-second pointer or digital presentation","Coordinated Universal Time only"],"a":1,"src":{"doc":"14 CFR 91.205","ref":"IFR instrument and equipment requirements","url":"https://www.ecfr.gov/current/title-14/section-91.205","quote":"A clock displaying hours, minutes, and seconds with a sweep-second pointer or digital presentation. (14 CFR 91.205(d)(6))"}},
    {"id":"ir-021","acs":"IR.II.A","q":"Which electrical-system item is required for IFR flight under 14 CFR 91.205(d)?","choices":["A second magneto","A generator or alternator of adequate capacity","A backup battery rated for two hours"],"a":1,"src":{"doc":"14 CFR 91.205","ref":"IFR instrument and equipment requirements","url":"https://www.ecfr.gov/current/title-14/section-91.205","quote":"Generator or alternator of adequate capacity. (14 CFR 91.205(d)(7))"}},
    {"id":"ir-022","acs":"IR.II.B","q":"Within what period must a VOR have been operationally checked and found within tolerance for use under IFR (when not maintained under an approved procedure)?","choices":["Within the preceding 90 days","Within the preceding 24 calendar months","Within the preceding 30 days"],"a":2,"src":{"doc":"14 CFR 91.171","ref":"VOR equipment check for IFR operations","url":"https://www.ecfr.gov/current/title-14/section-91.171","quote":"Has been operationally checked within the preceding 30 days, and was found to be within the limits of the permissible indicated bearing error set forth in paragraph (b) or (c) of this section. (14 CFR 91.171(a)(2))"}},
    {"id":"ir-023","acs":"IR.II.B","q":"When using a VOT or an FAA-approved test signal to check VOR equipment for IFR, what is the maximum permissible indicated bearing error?","choices":["Plus or minus 10 degrees","Plus or minus 6 degrees","Plus or minus 4 degrees"],"a":2,"src":{"doc":"14 CFR 91.171","ref":"VOR check tolerances","url":"https://www.ecfr.gov/current/title-14/section-91.171","quote":"Use, at the airport of intended departure, an FAA-operated or approved test signal or a test signal radiated by a certificated and appropriately rated radio repair station (the maximum permissible indicated bearing error is plus or minus 4 degrees). (14 CFR 91.171(b)(1))"}},
    {"id":"ir-024","acs":"IR.II.B","q":"When using a designated airborne checkpoint to check VOR equipment, what is the maximum permissible bearing error?","choices":["Plus or minus 6 degrees","Plus or minus 4 degrees","Plus or minus 8 degrees"],"a":0,"src":{"doc":"14 CFR 91.171","ref":"VOR check tolerances","url":"https://www.ecfr.gov/current/title-14/section-91.171","quote":"If neither a test signal nor a designated checkpoint on the surface is available, use an airborne checkpoint designated by the Administrator (the maximum permissible bearing error is plus or minus 6 degrees). (14 CFR 91.171(b)(3))"}},
    {"id":"ir-025","acs":"IR.II.B","q":"When a dual VOR system is checked by comparing one system against the other, what is the maximum permissible variation between the two indicated bearings?","choices":["4 degrees","6 degrees","2 degrees"],"a":0,"src":{"doc":"14 CFR 91.171","ref":"Dual system VOR check","url":"https://www.ecfr.gov/current/title-14/section-91.171","quote":"Both systems shall be tuned to the same VOR ground facility and note the indicated bearings to that station. The maximum permissible variation between the two indicated bearings is 4 degrees. (14 CFR 91.171(c))"}},
    {"id":"ir-026","acs":"IR.II.B","q":"After completing a VOR operational check for IFR, what must the person who made the check record?","choices":["Only the bearing error in the aircraft maintenance logbook","Nothing, unless the check failed","The date, place, bearing error, and sign the aircraft log or other record"],"a":2,"src":{"doc":"14 CFR 91.171","ref":"VOR check recordkeeping","url":"https://www.ecfr.gov/current/title-14/section-91.171","quote":"Each person making the VOR operational check, as specified in paragraph (b) or (c) of this section, shall enter the date, place, bearing error, and sign the aircraft log or other record. (14 CFR 91.171(d))"}},
    {"id":"ir-027","acs":"IR.III.A","q":"Before operating in controlled airspace under IFR, what two things must a person have?","choices":["A filed VFR flight plan and a transponder code","A filed IFR flight plan and an appropriate ATC clearance","Only a clearance; no flight plan is required in controlled airspace"],"a":1,"src":{"doc":"14 CFR 91.173","ref":"ATC clearance and flight plan required","url":"https://www.ecfr.gov/current/title-14/section-91.173","quote":"No person may operate an aircraft in controlled airspace under IFR unless that person has (a) Filed an IFR flight plan; and (b) Received an appropriate ATC clearance. (14 CFR 91.173)"}},
    {"id":"ir-028","acs":"IR.III.A","q":"While operating under IFR in controlled airspace, when must the pilot in command report unforecast weather conditions?","choices":["Only after landing","Only if specifically requested by ATC","As soon as possible"],"a":2,"src":{"doc":"14 CFR 91.183","ref":"IFR communications","url":"https://www.ecfr.gov/current/title-14/section-91.183","quote":"The pilot in command of each aircraft operated under IFR in controlled airspace must ensure that a continuous watch is maintained on the appropriate frequency and must report the following as soon as possible: Any unforecast weather conditions encountered. (14 CFR 91.183(b))"}},
    {"id":"ir-029","acs":"IR.III.A","q":"When must a pilot operating under IFR in controlled airspace report a malfunction of navigational, approach, or communication equipment to ATC?","choices":["Only during the postflight debrief","As soon as practical","Within 24 hours by telephone"],"a":1,"src":{"doc":"14 CFR 91.187","ref":"Malfunction reports","url":"https://www.ecfr.gov/current/title-14/section-91.187","quote":"The pilot in command of each aircraft operated in controlled airspace under IFR shall report as soon as practical to ATC any malfunctions of navigational, approach, or communication equipment occurring in flight. (14 CFR 91.187(a))"}},
    {"id":"ir-030","acs":"IR.III.B","q":"At or below 14,000 feet MSL, what is the standard inbound leg time in a holding pattern?","choices":["1 1/2 minutes","2 minutes","1 minute"],"a":2,"src":{"doc":"AIM 5-3-8","ref":"Holding timing","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"Inbound Leg. At or below 14,000 feet MSL: 1 minute. (AIM 5-3-8)"}},
    {"id":"ir-031","acs":"IR.III.B","q":"Above 14,000 feet MSL, what is the standard inbound leg time in a holding pattern?","choices":["3 minutes","1 minute","1 1/2 minutes"],"a":2,"src":{"doc":"AIM 5-3-8","ref":"Holding timing","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"Inbound Leg. Above 14,000 feet MSL: 1 1/2 minutes. (AIM 5-3-8)"}},
    {"id":"ir-032","acs":"IR.III.B","q":"Which describes the parallel holding entry procedure?","choices":["Fly directly to the fix and turn to follow the holding pattern","Turn to a heading to parallel the holding course outbound on the nonholding side for one minute, then turn in the direction of the holding pattern through more than 180 degrees and return to the fix or intercept the inbound course","Fly to the fix and turn outbound to a 30 degree teardrop heading on the holding side for one minute"],"a":1,"src":{"doc":"AIM 5-3-8","ref":"Holding entry procedures","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"Parallel Procedure. When approaching the holding fix from anywhere in sector (a), the parallel entry procedure would be to turn to a heading to parallel the holding course outbound on the nonholding side for one minute, turn in the direction of the holding pattern through more than 180 degrees, and return to the holding fix or intercept the holding course inbound. (AIM 5-3-8)"}},
    {"id":"ir-033","acs":"IR.III.B","q":"Which describes the teardrop holding entry procedure?","choices":["Fly to the fix, turn outbound to a heading for a 30 degree teardrop entry within the pattern on the holding side for one minute, then turn in the direction of the holding pattern to intercept the inbound course","Parallel the holding course on the nonholding side for one minute","Fly directly to the fix and turn to follow the pattern"],"a":0,"src":{"doc":"AIM 5-3-8","ref":"Holding entry procedures","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"Teardrop Procedure. When approaching the holding fix from anywhere in sector (b), the teardrop entry procedure would be to fly to the fix, turn outbound to a heading for a 30 degree teardrop entry within the pattern (on the holding side) for a period of one minute, then turn in the direction of the holding pattern to intercept the inbound holding course. (AIM 5-3-8)"}},
    {"id":"ir-034","acs":"IR.III.B","q":"At or below 6,000 feet MSL, what is the maximum holding airspeed applicable to all aircraft?","choices":["200 KIAS","230 KIAS","175 KIAS"],"a":0,"src":{"doc":"AIM 5-3-8","ref":"Maximum holding airspeeds","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"All aircraft may hold at the following altitudes and maximum holding airspeeds: MHA - 6,000' ... 200 [KIAS]. (AIM 5-3-8, TBL 5-3-2)"}},
    {"id":"ir-035","acs":"IR.III.B","q":"From 6,001 feet to 14,000 feet MSL, what is the maximum holding airspeed?","choices":["230 KIAS","200 KIAS","265 KIAS"],"a":0,"src":{"doc":"AIM 5-3-8","ref":"Maximum holding airspeeds","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"All aircraft may hold at the following altitudes and maximum holding airspeeds: 6,001' - 14,000' ... 230 [KIAS]. (AIM 5-3-8, TBL 5-3-2)"}},
    {"id":"ir-036","acs":"IR.III.B","q":"In a holding pattern, when does outbound leg timing begin?","choices":["Over or abeam the fix, whichever occurs later","Exactly one minute after passing the fix","When crossing the holding fix inbound"],"a":0,"src":{"doc":"AIM 5-3-8","ref":"Holding timing","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"Outbound leg timing begins over/abeam the fix, whichever occurs later. If the abeam position cannot be determined, start timing when turn to outbound is completed. (AIM 5-3-8)"}},
    {"id":"ir-037","acs":"IR.IV.A","q":"What is the purpose of cross-checking the flight instruments during instrument flight?","choices":["To allow the pilot to fly solely by reference to the attitude indicator","To detect and prevent fixation on a single instrument and to identify errors by comparing instruments","To reduce the workload by ignoring the secondary instruments"],"a":1,"src":{"doc":"FAA-H-8083-15B","ref":"Instrument Flying Handbook, instrument cross-check","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/FAA-H-8083-15B.pdf","quote":"Cross-checking, also called scanning, is the continuous and logical observation of instruments for attitude and performance information. (FAA-H-8083-15B)"}},
    {"id":"ir-038","acs":"IR.IV.A","q":"On the attitude indicator, which instrument is considered the primary control and performance reference for establishing and maintaining a desired attitude?","choices":["The turn coordinator","The vertical speed indicator","The attitude indicator"],"a":2,"src":{"doc":"FAA-H-8083-15B","ref":"Instrument Flying Handbook, attitude instrument flying","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/FAA-H-8083-15B.pdf","quote":"The attitude indicator is the only instrument that provides an immediate and direct indication of the aircraft's pitch and bank attitude. (FAA-H-8083-15B)"}},
    {"id":"ir-039","acs":"IR.IV.B","q":"During recovery from an unusual nose-high attitude in instruments, what coordinated control inputs are generally applied?","choices":["Reduce power, raise the nose, and bank steeply","Increase power, lower the nose, and level the wings","Maintain power and hold the existing attitude until airspeed stabilizes"],"a":1,"src":{"doc":"FAA-H-8083-15B","ref":"Instrument Flying Handbook, unusual attitude recovery","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/FAA-H-8083-15B.pdf","quote":"If the airspeed is decreasing, or below the desired airspeed, increase power (as necessary in proportion to the observed deceleration), apply forward elevator pressure to lower the nose and prevent a stall, and correct the bank by applying coordinated aileron and rudder pressure to level the wings. (FAA-H-8083-15B)"}},
    {"id":"ir-040","acs":"IR.IV.B","q":"During recovery from an unusual nose-low attitude in instruments, what coordinated control inputs are generally applied?","choices":["Add power and pull back immediately to arrest the descent","Hold the controls fixed until the airspeed returns to normal","Reduce power, level the wings, then raise the nose to level flight attitude"],"a":2,"src":{"doc":"FAA-H-8083-15B","ref":"Instrument Flying Handbook, unusual attitude recovery","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/FAA-H-8083-15B.pdf","quote":"If the airspeed is increasing, or above the desired airspeed, reduce power to prevent excessive airspeed and loss of altitude, correct the bank attitude with coordinated aileron and rudder pressure to level the wings, and raise the nose to level flight attitude with smooth back elevator pressure. (FAA-H-8083-15B)"}},
    {"id":"ir-041","acs":"IR.V.A","q":"What is a Final Approach Fix (FAF)?","choices":["The fix from which the final approach to an airport is executed and which identifies the beginning of the final approach segment","The first fix after the initial approach fix","The point where the missed approach begins"],"a":0,"src":{"doc":"Pilot/Controller Glossary","ref":"Final Approach Fix","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-f.html","quote":"FINAL APPROACH FIX- The fix from which the final approach (IFR) to an airport is executed and which identifies the beginning of the final approach segment. (Pilot/Controller Glossary)"}},
    {"id":"ir-042","acs":"IR.V.A","q":"On a nonprecision approach, how is the final approach fix typically depicted on government charts?","choices":["By a lightning bolt symbol","By a solid triangle","By the Maltese Cross symbol"],"a":2,"src":{"doc":"Pilot/Controller Glossary","ref":"Final Approach Fix","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-f.html","quote":"It is designated on Government charts by the Maltese Cross symbol for nonprecision approaches and the lightning bolt symbol, designating the PFAF, for precision approaches. (Pilot/Controller Glossary)"}},
    {"id":"ir-043","acs":"IR.V.B","q":"What is a procedure turn?","choices":["A maneuver prescribed when it is necessary to reverse direction to establish an aircraft on the intermediate approach segment or final approach course","A turn used to enter a holding pattern","A standard rate turn used only during missed approach"],"a":0,"src":{"doc":"Pilot/Controller Glossary","ref":"Procedure turn","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-p.html","quote":"PROCEDURE TURN- The maneuver prescribed when it is necessary to reverse direction to establish an aircraft on the intermediate approach segment or final approach course. (Pilot/Controller Glossary)"}},
    {"id":"ir-044","acs":"IR.V.B","q":"On a procedure turn, which elements are specified in the procedure, and which are left to the pilot?","choices":["Everything including the point of commencement is fixed by the procedure","The outbound course, direction of turn, distance, and minimum altitude are specified; the point of commencement and type and rate of turn are left to the pilot","Only the minimum altitude is specified; all else is at pilot discretion"],"a":1,"src":{"doc":"Pilot/Controller Glossary","ref":"Procedure turn","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-p.html","quote":"The outbound course, direction of turn, distance within which the turn must be completed, and minimum altitude are specified in the procedure. However, unless otherwise restricted, the point at which the turn may be commenced and the type and rate of turn are left to the discretion of the pilot. (Pilot/Controller Glossary)"}},
    {"id":"ir-045","acs":"IR.VI.A","q":"What is a Minimum Descent Altitude (MDA)?","choices":["The lowest altitude assignable for a radar vector","The lowest altitude, expressed in feet above mean sea level, to which descent is authorized on final approach or during circle-to-land maneuvering where no electronic glideslope is provided","The decision altitude on an ILS approach"],"a":1,"src":{"doc":"Pilot/Controller Glossary","ref":"Minimum Descent Altitude (MDA)","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-m.html","quote":"MINIMUM DESCENT ALTITUDE (MDA)- The lowest altitude, expressed in feet above mean sea level, to which descent is authorized on final approach or during circle-to-land maneuvering in execution of a standard instrument approach procedure where no electronic glideslope is provided. (Pilot/Controller Glossary)"}},
    {"id":"ir-046","acs":"IR.VI.A","q":"To descend below the MDA or continue below DA/DH on an instrument approach, the flight visibility must be at least what?","choices":["1 statute mile in all cases","3 statute miles regardless of the procedure","Not less than the visibility prescribed in the standard instrument approach being used"],"a":2,"src":{"doc":"14 CFR 91.175","ref":"Operation below DA/DH or MDA","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"The flight visibility is not less than the visibility prescribed in the standard instrument approach being used. (14 CFR 91.175(c)(2))"}},
    {"id":"ir-047","acs":"IR.VI.A","q":"Which is among the conditions that must be met to operate below MDA or continue below DA/DH on an instrument approach?","choices":["The aircraft has descended at least 500 feet per minute","The aircraft is continuously in a position from which a descent to a landing on the intended runway can be made at a normal rate of descent using normal maneuvers","ATC has issued a visual approach clearance"],"a":1,"src":{"doc":"14 CFR 91.175","ref":"Operation below DA/DH or MDA","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"The aircraft is continuously in a position from which a descent to a landing on the intended runway can be made at a normal rate of descent using normal maneuvers. (14 CFR 91.175(c)(1))"}},
    {"id":"ir-048","acs":"IR.VI.A","q":"When using the approach light system as the only visual reference, below what height may the pilot not descend unless the red terminating bars or red side row bars are also distinctly visible?","choices":["200 feet above the touchdown zone elevation","100 feet above the touchdown zone elevation","50 feet above the runway threshold"],"a":1,"src":{"doc":"14 CFR 91.175","ref":"Visual references for descent below DA/MDA","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"The approach light system, except that the pilot may not descend below 100 feet above the touchdown zone elevation using the approach lights as a reference unless the red terminating bars or the red side row bars are also distinctly visible and identifiable. (14 CFR 91.175(c)(3)(i))"}},
    {"id":"ir-049","acs":"IR.VI.A","q":"When it is necessary to use an instrument approach to a civil airport, what must each person operating an aircraft use?","choices":["A standard instrument approach procedure prescribed in part 97 for that airport, unless otherwise authorized by the FAA","Any approach the pilot deems appropriate for the conditions","A visual approach whenever the field is in sight"],"a":0,"src":{"doc":"14 CFR 91.175","ref":"Instrument approaches to civil airports","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"Unless otherwise authorized by the FAA, when it is necessary to use an instrument approach to a civil airport, each person operating an aircraft must use a standard instrument approach procedure prescribed in part 97 of this chapter for that airport. (14 CFR 91.175(a))"}},
    {"id":"ir-050","acs":"IR.VI.A","q":"Into which aircraft approach category does an aircraft fall if its approach speed (1.3 Vso) is 91 knots or more but less than 121 knots?","choices":["Category A","Category B","Category C"],"a":1,"src":{"doc":"Pilot/Controller Glossary","ref":"Aircraft Approach Category","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-a.html","quote":"Category B- Speed 91 knots or more but less than 121 knots. (Pilot/Controller Glossary)"}},
    {"id":"ir-051","acs":"IR.VI.A","q":"Aircraft approach categories are based on what speed?","choices":["The best rate-of-climb speed (Vy)","A speed of 1.3 times the stall speed in the landing configuration at maximum gross landing weight","The never-exceed speed (Vne)"],"a":1,"src":{"doc":"Pilot/Controller Glossary","ref":"Aircraft Approach Category","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-a.html","quote":"AIRCRAFT APPROACH CATEGORY- A grouping of aircraft based on a speed of 1.3 times the stall speed in the landing configuration at maximum gross landing weight. (Pilot/Controller Glossary)"}},
    {"id":"ir-052","acs":"IR.VI.A","q":"If a pilot must circle to land at a speed in excess of the upper limit of the aircraft's approach category speed range, which minimums must be used?","choices":["The minimums for the category corresponding to that higher speed","Category A minimums in all cases","The minimums for the aircraft's normal category regardless of speed"],"a":0,"src":{"doc":"Pilot/Controller Glossary","ref":"Aircraft Approach Category","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-a.html","quote":"If it is necessary to maneuver at speeds in excess of the upper limit of a speed range for a category, the minimums for the category for that speed must be used. (Pilot/Controller Glossary)"}},
    {"id":"ir-053","acs":"IR.VI.B","q":"What is a Decision Altitude (DA) on a precision or vertically guided approach?","choices":["The altitude at which the final approach fix is crossed","The altitude to which descent is authorized when no glideslope is provided","A specified altitude (MSL) at which the pilot must decide whether to continue the approach or initiate an immediate missed approach if the required visual references are not seen"],"a":2,"src":{"doc":"Pilot/Controller Glossary","ref":"Decision Altitude (DA)","url":"https://www.faa.gov/air_traffic/publications/atpubs/pcg_html/glossary-d.html","quote":"DECISION ALTITUDE (DA)- A specified altitude (mean sea level (MSL)) on an instrument approach procedure (ILS, GLS, vertically guided RNAV) at which the pilot must decide whether to continue the approach or initiate an immediate missed approach if the pilot does not see the required visual references. (Pilot/Controller Glossary)"}},
    {"id":"ir-054","acs":"IR.VI.B","q":"Per 14 CFR 1.1, how is decision altitude (DA) expressed, and decision height (DH)?","choices":["DA in feet above ground level; DH in feet above mean sea level","DA in feet above mean sea level; DH in feet above ground level","Both are expressed in feet above mean sea level"],"a":1,"src":{"doc":"14 CFR 1.1","ref":"Decision altitude and decision height definitions","url":"https://www.ecfr.gov/current/title-14/section-1.1","quote":"Decision altitude is expressed in feet above mean sea level. ... Decision height is expressed in feet above ground level. (14 CFR 1.1)"}},
    {"id":"ir-055","acs":"IR.VI.B","q":"Per 14 CFR 1.1, at the decision altitude on an instrument approach, the pilot must decide to do what if the required visual reference is not seen?","choices":["Continue to the runway threshold and then go around","Initiate an immediate missed approach","Level off and hold"],"a":1,"src":{"doc":"14 CFR 1.1","ref":"Decision altitude definition","url":"https://www.ecfr.gov/current/title-14/section-1.1","quote":"Decision altitude (DA) is a specified altitude in an instrument approach procedure at which the pilot must decide whether to initiate an immediate missed approach if the pilot does not see the required visual reference, or to continue the approach. (14 CFR 1.1)"}},
    {"id":"ir-056","acs":"IR.VI.C","q":"When must a pilot immediately execute the missed approach procedure with respect to the missed approach point?","choices":["Five seconds before reaching the missed approach point","Only after circling the airport once","Upon arrival at the missed approach point if the required conditions to continue are not met"],"a":2,"src":{"doc":"14 CFR 91.175","ref":"Missed approach procedures","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"Upon arrival at the missed approach point, including a DA/DH where a DA/DH is specified and its use is required, and at any time after that until touchdown. (14 CFR 91.175(e)(1)(ii))"}},
    {"id":"ir-057","acs":"IR.VI.C","q":"Each pilot operating a civil aircraft shall immediately execute an appropriate missed approach procedure when which of the following exists?","choices":["The aircraft is being operated below MDA and the requirements to operate below MDA are not met","ATC has not yet issued a landing clearance","The aircraft is high on the glidepath"],"a":0,"src":{"doc":"14 CFR 91.175","ref":"Missed approach procedures","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"Each pilot operating an aircraft shall immediately execute an appropriate missed approach procedure when either of the following conditions exist: Whenever operating an aircraft pursuant to paragraph (c) of this section ... and the requirements of that paragraph or section are not met ... When the aircraft is being operated below MDA. (14 CFR 91.175(e)(1)(i))"}},
    {"id":"ir-058","acs":"IR.VI.D","q":"During a circling approach, when must a pilot immediately execute a missed approach?","choices":["Only when the tower instructs a go-around","Whenever the aircraft passes abeam the runway threshold","Whenever an identifiable part of the airport is not distinctly visible to the pilot during the circling maneuver at or above MDA, unless the loss of sight is only from a normal bank during the circling approach"],"a":2,"src":{"doc":"14 CFR 91.175","ref":"Missed approach during circling","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"Whenever an identifiable part of the airport is not distinctly visible to the pilot during a circling maneuver at or above MDA, unless the inability to see an identifiable part of the airport results only from a normal bank of the aircraft during the circling approach. (14 CFR 91.175(e)(2))"}},
    {"id":"ir-059","acs":"IR.VI.E","q":"Among the visual references that allow descent below DA/DH or MDA, which of the following qualifies?","choices":["The airport beacon","The runway threshold","The wind sock"],"a":1,"src":{"doc":"14 CFR 91.175","ref":"Visual references for landing from an approach","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"At least one of the following visual references for the intended runway is distinctly visible and identifiable to the pilot: ... The threshold. (14 CFR 91.175(c)(3)(ii))"}},
    {"id":"ir-060","acs":"IR.VI.E","q":"Which of the following is a listed visual reference permitting continued descent to land from an instrument approach?","choices":["A taxiway centerline","The airport rotating beacon","The runway or runway markings"],"a":2,"src":{"doc":"14 CFR 91.175","ref":"Visual references for landing from an approach","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"At least one of the following visual references for the intended runway is distinctly visible and identifiable to the pilot: ... The runway or runway markings. (14 CFR 91.175(c)(3)(ix))"}},
    {"id":"ir-061","acs":"IR.VII.A","q":"If a two-way radio communications failure occurs in VFR conditions, or VFR conditions are encountered after the failure, what must the pilot do?","choices":["Continue the flight under VFR and land as soon as practicable","Continue the IFR flight plan to the destination regardless of conditions","Immediately squawk 7500 and land at the nearest airport"],"a":0,"src":{"doc":"14 CFR 91.185","ref":"Two-way radio communications failure, VFR conditions","url":"https://www.ecfr.gov/current/title-14/section-91.185","quote":"If the failure occurs in VFR conditions, or if VFR conditions are encountered after the failure, each pilot shall continue the flight under VFR and land as soon as practicable. (14 CFR 91.185(b))"}},
    {"id":"ir-062","acs":"IR.VII.A","q":"After a two-way radio communications failure in IFR conditions, if being radar vectored when the failure occurs, what route should the pilot fly?","choices":["Return directly to the departure airport","By the direct route from the point of radio failure to the fix, route, or airway specified in the vector clearance","Continue the radar vector heading until reaching the destination"],"a":1,"src":{"doc":"14 CFR 91.185","ref":"Lost communications route","url":"https://www.ecfr.gov/current/title-14/section-91.185","quote":"If being radar vectored, by the direct route from the point of radio failure to the fix, route, or airway specified in the vector clearance. (14 CFR 91.185(c)(1)(ii))"}},
    {"id":"ir-063","acs":"IR.VII.A","q":"After a two-way radio communications failure in IFR conditions, what altitude should the pilot fly for each route segment?","choices":["The lowest of the assigned, minimum, and expected altitudes","The highest of the assigned altitude, the minimum IFR altitude, or the altitude ATC advised may be expected","Whatever altitude the pilot last flew before the failure"],"a":1,"src":{"doc":"14 CFR 91.185","ref":"Lost communications altitude","url":"https://www.ecfr.gov/current/title-14/section-91.185","quote":"Altitude. At the highest of the following altitudes or flight levels for the route segment being flown: (i) The altitude or flight level assigned in the last ATC clearance received; (ii) The minimum altitude for IFR operations; or (iii) The altitude or flight level ATC has advised may be expected in a further clearance. (14 CFR 91.185(c)(2))"}},
    {"id":"ir-064","acs":"IR.VII.A","q":"After lost communications, if the clearance limit is a fix from which an approach begins, when should the pilot commence descent and approach?","choices":["Immediately upon reaching the clearance limit, regardless of timing","Only after holding for 30 minutes at the clearance limit","As close as possible to the expect-further-clearance time, or if none was received, as close as possible to the ETA calculated from the filed or amended estimated time en route"],"a":2,"src":{"doc":"14 CFR 91.185","ref":"Lost communications, leave clearance limit","url":"https://www.ecfr.gov/current/title-14/section-91.185","quote":"When the clearance limit is a fix from which an approach begins, commence descent or descent and approach as close as possible to the expect-further-clearance time if one has been received, or if one has not been received, as close as possible to the estimated time of arrival as calculated from the filed or amended (with ATC) estimated time en route. (14 CFR 91.185(c)(3)(i))"}},
    {"id":"ir-065","acs":"IR.VII.A","q":"After a lost communications event in IFR conditions, if no route was assigned and ATC did not advise a route to expect, what route should the pilot fly?","choices":["The route filed in the flight plan","Direct to the nearest VOR","Any route that keeps the aircraft in VFR conditions"],"a":0,"src":{"doc":"14 CFR 91.185","ref":"Lost communications route","url":"https://www.ecfr.gov/current/title-14/section-91.185","quote":"In the absence of an assigned route or a route that ATC has advised may be expected in a further clearance, by the route filed in the flight plan. (14 CFR 91.185(c)(1)(iv))"}},
    {"id":"ir-066","acs":"IR.VII.D","q":"If a navigational, approach, or communication equipment malfunction occurs in flight under IFR in controlled airspace, what is the pilot in command required to do?","choices":["Report the malfunction to ATC as soon as practical","Land immediately at the nearest airport","Continue without reporting unless the malfunction affects the approach"],"a":0,"src":{"doc":"14 CFR 91.187","ref":"Malfunction reports","url":"https://www.ecfr.gov/current/title-14/section-91.187","quote":"The pilot in command of each aircraft operated in controlled airspace under IFR shall report as soon as practical to ATC any malfunctions of navigational, approach, or communication equipment occurring in flight. (14 CFR 91.187(a))"}},
    {"id":"ir-067","acs":"IR.VII.D","q":"Loss of the vacuum-driven attitude indicator and heading indicator (partial panel) requires the pilot to rely on which backup instruments for bank information in a typical analog cockpit?","choices":["The vertical speed indicator and altimeter","The airspeed indicator alone","The turn coordinator (or turn-and-slip indicator) and magnetic compass"],"a":2,"src":{"doc":"FAA-H-8083-15B","ref":"Instrument Flying Handbook, partial panel","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/FAA-H-8083-15B.pdf","quote":"The turn coordinator (TC) shows the rate of turn and the quality of the turn (coordination). (FAA-H-8083-15B)"}},
    {"id":"ir-068","acs":"IR.VIII.A","q":"During postflight, which is the appropriate practice regarding aircraft discrepancies discovered during the flight?","choices":["Report only discrepancies that occurred on the ground","Record and report any equipment or instrument discrepancies so they can be corrected","Ignore minor discrepancies if the flight was completed safely"],"a":1,"src":{"doc":"14 CFR 91.187","ref":"Malfunction reports","url":"https://www.ecfr.gov/current/title-14/section-91.187","quote":"The pilot in command of each aircraft operated in controlled airspace under IFR shall report as soon as practical to ATC any malfunctions of navigational, approach, or communication equipment occurring in flight. (14 CFR 91.187(a))"}},
    {"id":"ir-069","acs":"IR.I.A","q":"The aeronautical knowledge areas for the instrument rating include which of the following?","choices":["Recognition of critical weather situations and windshear avoidance","Multiengine systems and propeller feathering","Aerobatic maneuver theory"],"a":0,"src":{"doc":"14 CFR 61.65","ref":"Aeronautical knowledge for the instrument rating","url":"https://www.ecfr.gov/current/title-14/section-61.65","quote":"A person who applies for an instrument rating must have received and logged ground training ... on the following aeronautical knowledge areas: ... Recognition of critical weather situations and windshear avoidance. (14 CFR 61.65(b)(8))"}},
    {"id":"ir-070","acs":"IR.I.A","q":"Within what period before the practical test must an applicant for the instrument-airplane rating receive 3 hours of instrument flight training from an authorized instructor?","choices":["Within 6 calendar months before the date of the practical test","Within 60 days before the date of the practical test, in actual conditions only","Within 2 calendar months before the date of the practical test"],"a":2,"src":{"doc":"14 CFR 61.65","ref":"Recent instruction before the practical test","url":"https://www.ecfr.gov/current/title-14/section-61.65","quote":"Three hours of instrument flight training from an authorized instructor in an airplane that is appropriate to the instrument-airplane rating within 2 calendar months before the date of the practical test. (14 CFR 61.65(d)(2)(i))"}}
  ]
};
